return [
  {
    json: {
      owner: 'REPLACE_WITH_GITHUB_USERNAME',
      repo: 'REPLACE_WITH_REPO_NAME',
      workflow_id: 'run_clara_pipeline.yml',
      ref: 'main',
      token: 'REPLACE_WITH_GITHUB_PAT'
    }
  }
];

const cfg = $json;

if (
  String(cfg.owner || '').startsWith('REPLACE_') ||
  String(cfg.repo || '').startsWith('REPLACE_') ||
  String(cfg.token || '').startsWith('REPLACE_')
) {
  throw new Error('Update owner/repo/token in Set GitHub Config node before running.');
}

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.github.com/repos/${cfg.owner}/${cfg.repo}/actions/workflows/${cfg.workflow_id}/dispatches`,
  headers: {
    Authorization: `Bearer ${cfg.token}`,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  body: { ref: cfg.ref },
  json: true,
  resolveWithFullResponse: true,
  simple: false
});

return [
  {
    json: {
      ...cfg,
      dispatch_status_code: response.statusCode,
      dispatched: response.statusCode === 204
    }
  }
];

const cfg = $json;

const runs = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.github.com/repos/${cfg.owner}/${cfg.repo}/actions/workflows/${cfg.workflow_id}/runs?per_page=1`,
  headers: {
    Authorization: `Bearer ${cfg.token}`,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  json: true
});

const run = (runs.workflow_runs || [])[0] || null;

return [
  {
    json: {
      ...cfg,
      latest_run_id: run ? run.id : null,
      latest_run_status: run ? run.status : null,
      latest_run_conclusion: run ? run.conclusion : null,
      latest_run_url: run ? run.html_url : null
    }
  }
];

const j = $json;

return [
  {
    json: {
      summary: j.dispatched
        ? 'Pipeline dispatch succeeded. Open latest_run_url to monitor execution and download artifacts when complete.'
        : 'Dispatch failed. Check PAT scopes (repo, workflow) and repository/workflow name.',
      owner: j.owner,
      repo: j.repo,
      workflow_id: j.workflow_id,
      dispatch_status_code: j.dispatch_status_code,
      latest_run_status: j.latest_run_status,
      latest_run_conclusion: j.latest_run_conclusion,
      latest_run_url: j.latest_run_url
    }
  }
];
